--------------------------------------------------------
-- Synchronize temp table and real table by            --
-- inserting, deleting, and updating as necessary     --
--------------------------------------------------------

INSERT INTO PSP_ENTITLEMENT_CODE
(ENTITLEMENT_CODE_SEQ, CREATED_DATE, MODIFIED_DATE, EDITION_TYPE, NUMBER_OF_EMPLOYEES_TYPE, QUICK_BOOKS_SUBTYPE, SUBTYPE_DESCRIPTION, ASSET_ITEM_CD, ASSET_ITEM_NUMBER, IS_PRIMARY, VERSION, IS_USAGE_BILLING, IS_FIRST_USAGE_FREE, BILLING_FREQUENCY_TYPE, ASSET_TYPE_CD)
  SELECT
    ENTITLEMENT_CODE_SEQ, CREATED_DATE, MODIFIED_DATE, EDITION_TYPE, NUMBER_OF_EMPLOYEES_TYPE, QUICK_BOOKS_SUBTYPE, SUBTYPE_DESCRIPTION, ASSET_ITEM_CD, ASSET_ITEM_NUMBER, IS_PRIMARY, VERSION, IS_USAGE_BILLING, IS_FIRST_USAGE_FREE, BILLING_FREQUENCY_TYPE, ASSET_TYPE_CD
  FROM
    TEMP_PSP_ENTITLEMENT_CODE tt
  WHERE
    tt.ENTITLEMENT_CODE_SEQ NOT IN (SELECT ENTITLEMENT_CODE_SEQ FROM PSP_ENTITLEMENT_CODE)
;

DELETE FROM PSP_ENTITLEMENT_CODE
WHERE ENTITLEMENT_CODE_SEQ NOT IN (SELECT ENTITLEMENT_CODE_SEQ FROM TEMP_PSP_ENTITLEMENT_CODE)
;

UPDATE PSP_ENTITLEMENT_CODE rt
SET ( ENTITLEMENT_CODE_SEQ, EDITION_TYPE, NUMBER_OF_EMPLOYEES_TYPE, QUICK_BOOKS_SUBTYPE, SUBTYPE_DESCRIPTION, ASSET_ITEM_CD, ASSET_ITEM_NUMBER, IS_PRIMARY, VERSION, IS_USAGE_BILLING, IS_FIRST_USAGE_FREE, BILLING_FREQUENCY_TYPE, ASSET_TYPE_CD) =
(SELECT   tt.ENTITLEMENT_CODE_SEQ, tt.EDITION_TYPE, tt.NUMBER_OF_EMPLOYEES_TYPE, tt.QUICK_BOOKS_SUBTYPE, tt.SUBTYPE_DESCRIPTION, tt.ASSET_ITEM_CD, tt.ASSET_ITEM_NUMBER, tt.IS_PRIMARY, tt.VERSION, tt.IS_USAGE_BILLING, tt.IS_FIRST_USAGE_FREE, tt.BILLING_FREQUENCY_TYPE, tt.ASSET_TYPE_CD
FROM TEMP_PSP_ENTITLEMENT_CODE tt WHERE tt.ENTITLEMENT_CODE_SEQ = rt.ENTITLEMENT_CODE_SEQ)
;



